<div class="page-header"><div><h2 class="page-title">Creer une relation post / tag</h2><p class="page-meta">Associez un article a un tag.</p></div></div><form action="/admin/post-tags"class="card form-card"method="post"><div class="form-field"><label for="post_id">Article</label> <select class="form-select"id="post_id"name="post_id"required><option value="">-- Choisir un article --</option><?php foreach($posts as $post): ?><option value="<?=(int)$post['id']?>">#<?=(int)$post['id']?>-<?=htmlspecialchars($post['title'])?></option><?php endforeach; ?></select></div><div class="form-field"><label for="tag_id">Tag</label> <select class="form-select"id="tag_id"name="tag_id"required><option value="">-- Choisir un tag --</option><?php foreach($tags as $tag): ?><option value="<?=(int)$tag['id']?>">#<?=(int)$tag['id']?>-<?=htmlspecialchars($tag['name'])?></option><?php endforeach; ?></select></div><button class="btn btn-primary"type="submit">Enregistrer</button> <a class="btn btn-ghost"href="/admin/post-tags">Annuler</a></form>